func:
// Haal de globale MID variabele op
let mid = global.get("mid") || 0;

// Stel de constante Dev in (start met 36)
const Dev = "ASSET_ID_START_MET_36";

// PF / spanning
const COSPHI = 0.97;
const U_PHASE = 230; // fase-nul
const AH_TO_KWH = (U_PHASE * COSPHI) / 1000; // 0.2231

// Definieer de mapping van datatypes naar ID's
const idMapping = {
    "current_chn1": 3300,
    "current_chn1_total": 3310,
    "current_chn2": 3400,
    "current_chn2_total": 3410,
    "current_chn3": 3500,
    "current_chn3_total": 3510,
    // zelf berekend verbruik (kWh totalizer)
    "consumption_kwh_total": 4600,
    "bandwidth": 5100,
    "spreadFactor": 5200,
    "freq": 5300,
    "snr": 5400,
    "rssi": 5500
};
const normalizedIdMapping = Object.create(null);
for (const [k, v] of Object.entries(idMapping)) {
    normalizedIdMapping[k.toLowerCase()] = v;
}

// Begin met het resultaat-object
let result = {
    MID: mid,
    D: [
        {
            Dev: Dev,
            ED: [],
            MD: []
        }
    ]
};

// Timestamp van ontvangst
if (msg.time) {
    const date = new Date(msg.time);
    if (!isNaN(date.getTime())) {
        result.D[0].TS = date.toISOString();
    }
}

// Haal alle key-value paren uit de payload
let payloadData = msg.object;

// We capteren de 3 Ah totalizers hier
let ah1 = null, ah2 = null, ah3 = null;

if (payloadData && typeof payloadData === "object") {
    for (const [key, raw] of Object.entries(payloadData)) {
        const normalizedKey = key.toLowerCase();
        const id = normalizedIdMapping[normalizedKey];
        if (id === undefined) continue;

        let val = Number(raw);
        if (!Number.isFinite(val)) continue;

        // onthoud totals
        if (normalizedKey === "current_chn1_total") ah1 = val;
        if (normalizedKey === "current_chn2_total") ah2 = val;
        if (normalizedKey === "current_chn3_total") ah3 = val;

        result.D[0].MD.push({ Id: id, Val: val });
    }
}

// Voeg zelf berekende kWh totalizer toe (Id 4600)
if (Number.isFinite(ah1) && Number.isFinite(ah2) && Number.isFinite(ah3)) {
    const kwhTotal = (ah1 + ah2 + ah3) * AH_TO_KWH;
    result.D[0].MD.push({
        Id: 4600,
        Val: kwhTotal
    });
}

// Haal bandwidth en spreadfactor uit msg.dr
if (msg.dr && typeof msg.dr === "object") {
    for (const key of ["bandwidth", "spreadFactor"]) {
        if (!Object.prototype.hasOwnProperty.call(msg.dr, key)) continue;
        const normalizedKey = key.toLowerCase();
        const id = normalizedIdMapping[normalizedKey];
        if (id === undefined) continue;

        const val = Number(msg.dr[key]);
        if (!Number.isFinite(val)) continue;

        result.D[0].MD.push({ Id: id, Val: val });
    }
}

// Haal freq, snr en rssi UIT msg zelf
for (const key of ["freq", "snr", "rssi"]) {
    if (!Object.prototype.hasOwnProperty.call(msg, key)) continue;
    const normalizedKey = key.toLowerCase();
    const id = normalizedIdMapping[normalizedKey];
    if (id === undefined) continue;

    const val = Number(msg[key]);
    if (!Number.isFinite(val)) continue;

    result.D[0].MD.push({ Id: id, Val: val });
}

// Verhoog de MID en sla deze op in de globale context
global.set("mid", mid + 1);

// Stel de nieuwe payload in
msg.payload = result;

return msg;
